import { portfolioConfig } from "../portfolio.config";

export default function injectConfig() {
  // Update document metadata
  document.title = `${portfolioConfig.name} | ${portfolioConfig.title}`;
  
  const descriptionMeta = document.querySelector('meta[name="description"]');
  if (descriptionMeta) {
    descriptionMeta.setAttribute("content", `Portfolio of ${portfolioConfig.name} - ${portfolioConfig.title}`);
  }
  
  const keywordsMeta = document.querySelector('meta[name="keywords"]');
  if (keywordsMeta) {
    keywordsMeta.setAttribute("content", `${portfolioConfig.name}, portfolio, developer, AI, Full-Stack`);
  }

  // Walk DOM to replace text content
  const walkText = (node) => {
    if (node.nodeType === Node.TEXT_NODE) {
      let text = node.nodeValue;
      if (text.includes("NAME_PLACEHOLDER")) {
        text = text.replace(/NAME_PLACEHOLDER/g, portfolioConfig.name);
      }
      if (text.includes("TITLE_PLACEHOLDER")) {
        text = text.replace(/TITLE_PLACEHOLDER/g, portfolioConfig.title);
      }
      if (text.includes("EMAIL_PLACEHOLDER")) {
        text = text.replace(/EMAIL_PLACEHOLDER/g, portfolioConfig.email);
      }
      node.nodeValue = text;
    } else {
      for (let child of node.childNodes) {
        walkText(child);
      }
    }
  };
  walkText(document.body);

  // Update elements with data-src attributes
  const srcElements = document.querySelectorAll("[data-src]");
  srcElements.forEach((el) => {
    let val = el.getAttribute("data-src");
    let updated = val;
    if (updated.includes("PROFILE_IMAGE_PLACEHOLDER")) {
      updated = updated.replace(/PROFILE_IMAGE_PLACEHOLDER/g, portfolioConfig.profileImage);
    }
    if (updated.includes("STAMPEDE_IMAGE_PLACEHOLDER")) {
      updated = updated.replace(/STAMPEDE_IMAGE_PLACEHOLDER/g, portfolioConfig.projects.stampede);
    }
    if (updated.includes("FLOATCHAT_IMAGE_PLACEHOLDER")) {
      updated = updated.replace(/FLOATCHAT_IMAGE_PLACEHOLDER/g, portfolioConfig.projects.floatchat);
    }
    if (updated.includes("QUERYBOT_IMAGE_PLACEHOLDER")) {
      updated = updated.replace(/QUERYBOT_IMAGE_PLACEHOLDER/g, portfolioConfig.projects.queryBot);
    }
    el.setAttribute("src", updated);
  });

  // Update elements with data-href attributes
  const hrefElements = document.querySelectorAll("[data-href]");
  hrefElements.forEach((el) => {
    let val = el.getAttribute("data-href");
    let updated = val;
    if (updated.includes("EMAIL_PLACEHOLDER")) {
      updated = updated.replace(/EMAIL_PLACEHOLDER/g, portfolioConfig.email);
    }
    if (updated.includes("GITHUB_PLACEHOLDER")) {
      updated = updated.replace(/GITHUB_PLACEHOLDER/g, portfolioConfig.github);
    }
    if (updated.includes("LINKEDIN_PLACEHOLDER")) {
      updated = updated.replace(/LINKEDIN_PLACEHOLDER/g, portfolioConfig.linkedin);
    }
    if (updated.includes("LEETCODE_PLACEHOLDER")) {
      updated = updated.replace(/LEETCODE_PLACEHOLDER/g, portfolioConfig.leetcode);
    }
    if (updated.includes("RESUME_PLACEHOLDER")) {
      updated = updated.replace(/RESUME_PLACEHOLDER/g, portfolioConfig.resume);
    }
    el.setAttribute("href", updated);
  });
}
